// frontend/src/components/MovieCard.js
import React from 'react';

function MovieCard({ movie, onEdit, onDelete }) {
    return (
        <div className="movie-card">
            <div className="movie-card-header">
                <h3>{movie.title}</h3>
                <div className="movie-rating">{movie.rating} / 10</div>
            </div>
            <div className="movie-card-details">
                <p><strong>Director:</strong> {movie.director}</p>
                <p><strong>Release Year:</strong> {movie.releaseYear}</p>
                <p><strong>Genre:</strong> {movie.genre}</p>
                <p className="movie-id">ID: {movie.movieID}</p>
            </div>
            <div className="movie-card-actions">
                <button className="btn-edit" onClick={() => onEdit(movie)}>Edit</button>
                <button className="btn-delete" onClick={() => onDelete(movie.movieID)}>Delete</button>
            </div>
        </div>
    );
}

export default MovieCard;
